#include <bits/stdc++.h>
using namespace std;
#define int long long
int a,m;
string b;
int ol(int n){
	int res=n;
	for(int i=2;i*i<=n;i++){
		if(n%i==0){
			res=res/i*(i-1);
			while(n%i==0){
				n/=i;
			}
		}
	}
	if(n>1){
		res=res/n*(n-1);
	}
	return res;
}
int qpow(int a,int b,int p) {
	int res=1;
	a%=p;
	while (b) {
		if (b&1)res=res*a%p;
		a=a*a%p;
		b>>=1;
	}
	return res;
}
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>a>>m>>b;
	int m1=m;
	m=ol(m);
	int x=0,fl=0;
	for(int i=0;i<b.size();i++){
		x=x*10+(b[i]-'0');
		if(x>=m){
			fl=1;
			x%=m;
		}
	}
	if(fl){
		cout<<qpow(a,x+m,m1);
	}else{
		cout<<qpow(a,x,m1);
	}
	return 0;
}
